var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연! 듣고 있나?","JPN":"カナミ・キズナ！　聞いているか？","ENG":"Lee Sooyeon! Can you hear me?","TWN":"李秀妍！能聽到嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"드래곤 버스터가 필요하다! 당장 이쪽 좌표로 전송하도록!","JPN":"ドラゴンバスターを要請する！　直ちにこちらの座標に送ってくれ！","ENG":"I need the Dragon Buster! Send it to my coordinates, now!","TWN":"我需要屠龍者！馬上傳送到這裡的座標！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"통신은...... 아직 불능인가?","JPN":"通信が……まだ使えないのか？","ENG":"The comms... Is it still down?","TWN":"通信……還沒恢復？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......할 수 없군.","JPN":"……仕方ないな。","ENG":"Oh well...","TWN":"……沒辦法了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"드래곤 버스터 없이 클리포트 인자를 사용하면 반동이 크겠지만......","JPN":"ドラゴンバスターなしでクリフォト・ファクターを使うと反動は大きいが……","ENG":"The recoil will be immense if I use the Qliphoth Factor without the Dragon Buster...","TWN":"沒有屠龍者的狀態下使用逆卡巴拉因子的話，反作用力會很大，不過……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어느 정도 피해는 감수하더라도, 여기서 끝낸다.","JPN":"ある程度の被害を覚悟して、ここで終わらせてやる。","ENG":"But this must end here and now, no matter the cost.","TWN":"就算如此，一定要在這裡處理掉。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>제 1 운명구속구 그람 해제</color>","JPN":"<color=#ffd34c>第一運命拘束具グラム解除。</color>","ENG":"<color=#ffd34c>The first restrainer \\"Fate Binder\\" Gram, released.</color>","TWN":"<color=#ffd34c>第1命運拘束器格拉墨。解除 。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_21"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>제 2 숙명구속구 발뭉 해제</color>","JPN":"<color=#ffd34c>第二宿命拘束具バルムンク解除。</color>","ENG":"<color=#ffd34c>The second restrainer \\"Destiny Fetter\\" Balmung, released.</color>","TWN":"<color=#ffd34c>第2宿命拘束器巴鲁姆克 。解除。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_21"},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"길게 끌지 않겠다! 단숨에 끝내 주지!","JPN":"長引かせない！　一気に終わらせてやるぞ！","ENG":"I won't drag this out! I'll finish you at once!","TWN":"不能拖延！要速戰速決！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내 공격을 막았다고......? 겨우 언데드 따위가?","JPN":"攻撃を防いだ……？　たかがアンデッドごときが？","ENG":"She... blocked my attack? A mere undead?","TWN":"竟然擋住了我的攻擊……？區區亡靈？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......아니, 그럴 리가 없지.","JPN":"いや、あり得ない……","ENG":"No... That can't be right.","TWN":"……不，不可能。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"누구냐! 모습을 드러내라!","JPN":"誰だ！　姿を現せ！","ENG":"Who are you? Show yourself!","TWN":"你是誰！亮出你的真面目吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"죄송합니다. 갑작스러운 일이라 놀라셨겠네요.","JPN":"ごめんなさい。突然だったから驚いたでしょう。","ENG":"Apologies. You must be startled from the abruptness of it all.","TWN":"抱歉，我嚇到你了吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"하지만 이 아이에겐 아직 사명이 남아 있어요. 당신의 손에 죽게 내버려 둘 수는 없습니다.","JPN":"しかしこの子にはまだ使命が残っています。あなたの手によってここで死なせるわけにはいきません。","ENG":"But this child still has a calling to fulfill. I cannot let her perish by your hand.","TWN":"但是這孩子還有未完成的使命，可不能讓她死在你的手上。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너는......","JPN":"お前は……","ENG":"You...","TWN":"你是……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그렇군. 네가 저 침식체를 리치로 만든 강령술사였나.","JPN":"そうか。お前があの侵食体をリッチにした降霊術師なんだな。","ENG":"I see. You must be the necromancer who turned that C.O. into a Lich.","TWN":"原來如此，你就是將那個侵蝕體變成巫妖的降靈術師吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"모습을 드러냈다는 건, 날 상대할 자신이 있다는 뜻이겠지?","JPN":"姿を現したのは私を相手に生き残る自信があるということだな？","ENG":"Seeing as you revealed yourself, you must think you stand a chance against me, huh?","TWN":"你敢出現在我面前，說明對自己的實力很有自信？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"당신의 힘은 아직 완전하지 않아요.","JPN":"あなたの力はまだ完全ではありません。","ENG":"Your powers are not yet complete.","TWN":"你的力量還不完整。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"그 힘을 보완해 줄 수 있는 무기도 지금은 지니지 않은 상태죠.","JPN":"その力を補ってくれる武器も今は持っていないでしょう。","ENG":"Neither do you currently possess the weapon to supplement your shortcomings.","TWN":"能完善你力量的武器你也沒帶在身上。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"그런 불완전한 발키리라면......","JPN":"そんな不完全なヴァルキリーなら……","ENG":"Against such an incomplete Valkyrie...","TWN":"這樣不完整的女武神……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"네. 제 힘으로도 충분히 상대할 수 있습니다.","JPN":"はい。私の力でも十分相手できるでしょう。","ENG":"Yes. I believe I can deftly best you in battle.","TWN":"是的。以我的力量足以對抗。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"건방진......!!","JPN":"生意気な……！！","ENG":"You arrogant fool!","TWN":"真是傲慢……！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};